ga_o(){return"\u062f\u06d5\u062a\u0648\u0627\u0646\u06cc\u062a \u0647\u06d5\u0631 \u06a9\u0627\u062a\u06ce\u06a9 \u0628\u06d5 \u0626\u06cc\u0645\u06d5\u06cc\u06b5 \u0648 \u0648\u0634\u06d5\u06cc \u0646\u0647\u06ce\u0646\u06cc\u062a \u062f\u0648\u0648\u0628\u0627\u0631\u06d5 \u0628\u0686\u06cc\u062a\u06d5\u0648\u06d5 \u0698\u0648\u0648\u0631\u06d5\u0648\u06d5."},
ga_j(){return"\u0647\u06d5\u0698\u0645\u0627\u0631"},
ga_k(){return"\u0647\u06d5\u06b5\u0628\u0698\u0627\u0631\u062f\u0646\u06d5\u06a9\u0627\u0646"},
ga_l(){return"\u067e\u0634\u062a\u06af\u06cc\u0631\u06cc"},
ga_a(){return"\u0645\u06ce\u0648\u0627\u0646"},
ga_r(){return"\u0626\u0627\u06af\u0627\u062f\u0627\u0631\u06cc\u06d5\u06a9\u0627\u0646"},
gJW(){return"\u0648\u0631\u062f\u06d5\u06a9\u0627\u0631\u06cc \u0647\u06d5\u0698\u0645\u0627\u0631"},
gQn(){return"\u067e\u0627\u0634\u06d5\u06a9\u06d5\u0648\u062a\u06a9\u0631\u062f\u0646\u06cc \u06af\u06c6\u0695\u0627\u0646\u06a9\u0627\u0631\u06cc\u06cc\u06d5\u06a9\u0627\u0646"},
gQp(){return"\u067e\u0631\u06c6\u0641\u0627\u06cc\u0644\u06d5\u06a9\u06d5 \u0646\u0648\u06ce\u06a9\u0631\u0627\u06cc\u06d5\u0648\u06d5."},
gQc(){return"\u0646\u0627\u0648\u0686\u06d5\u06cc \u0645\u06d5\u062a\u0631\u0633\u06cc"},
